#### 4.2 л§Өм№ӯ м•Ңкі лҰ¬мҰҳ мғҒм„ё лЎңм§Ғ
```
Input: userId (лҢҖмғҒ мӮ¬мҡ©мһҗ), preferences (м„ нҳёлҸ„)
Output: matchedUserId (л§Өм№ӯлҗң мӮ¬мҡ©мһҗ) лҳҗлҠ” null

Step 1: лҢҖкё° мӨ‘мқё мӮ¬мҡ©мһҗ лӘ©лЎқ мЎ°нҡҢ
  SELECT * FROM matching_queue
  WHERE status = WAITING AND user_id != {userId}

Step 2: м„ нҳёлҸ„ н•„н„°л§Ғ
  FOR EACH user IN waitingUsers:
    IF meetsPreferences(user, preferences):
      ADD user TO candidates

Step 3: л§Өм№ӯ м җмҲҳ кі„мӮ° (мҡ°м„ мҲңмң„)
  score = 0
  score += (м—°л № м„ нҳёлҸ„ мқјм№ҳлҸ„) * 0.3
  score += (м§Җм—ӯ м„ нҳёлҸ„ мқјм№ҳлҸ„) * 0.2
  score += (м„ұлі„ м„ нҳёлҸ„ мқјм№ҳлҸ„) * 0.2
  score += (л§Өл„Ҳ м җмҲҳ) * 0.15
  score += (кіөнҶө кҙҖмӢ¬мӮ¬ мҲҳ) * 0.15

Step 4: мөңкі  м җмҲҳ мӮ¬мҡ©мһҗ м„ нғқ
  bestMatch = candidates.sortBy(score).first()

Step 5: м–‘л°©н–Ҙ кІҖмҰқ
  - мғҒлҢҖл°©мқҙ лӮҙ мЎ°кұҙмқ„ л§ҢмЎұн•ҳлҠ”к°Җ?
  - мқҙлҜё л§Өм№ӯлҗң м Ғмқҙ м—ҶлҠ”к°Җ?
  - кұ°м Ҳ лӘ©лЎқм—җ м—ҶлҠ”к°Җ?

Step 6: л§Өм№ӯ мғқм„ұ
  INSERT INTO matching (user_id_1, user_id_2, status, expire_at)
  VALUES (userId, bestMatch.id, 'PENDING_ACCEPT', NOW() + 2min)
```

