**мҳҲмғҒ Service кө¬мЎ°**:
```kotlin
@Service
class MatchingService(
    private val matchingRepository: MatchingRepository,
    private val matchingQueueRepository: MatchingQueueRepository,
    private val userService: UserService,
    private val applicationEventPublisher: ApplicationEventPublisher,
) {

    @Transactional
    fun enqueueMatching(userId: String, preferences: MatchingPreference): MatchingQueueEntity {
        // 1. кё°мЎҙ нҒҗ нҷ•мқё
        val existing = matchingQueueRepository.findByUserIdAndStatus(userId, WAITING)
        if (existing != null) throw AlreadyInQueueException()

        // 2. мғҲ нҒҗ н•ӯлӘ© мғқм„ұ
        val queueEntity = MatchingQueueEntity(
            userId = userId,
            preferences = preferences.toJson(),
            status = WAITING,
        )
        return matchingQueueRepository.save(queueEntity)
    }

    @Transactional
    fun findMatching(userId: String): MatchingEntity? {
        // 1. нҒҗм—җм„ң лҢҖкё° мӨ‘мқё мӮ¬мҡ©мһҗ м°ҫкё°
        val queue = matchingQueueRepository.findByUserIdAndStatus(userId, WAITING)
            ?: throw NotInQueueException()

        // 2. л§Өм№ӯ м•Ңкі лҰ¬мҰҳ: м„ нҳёлҸ„м—җ л§һлҠ” лҢҖмғҒ м°ҫкё°
        val candidates = findCandidates(userId, queue.preferences)
        val matchedUser = selectBestMatch(candidates)
            ?: return null  // л§Өм№ӯ лҢҖмғҒ м—ҶмқҢ

        // 3. л§Өм№ӯ мғқм„ұ
        val matching = MatchingEntity(
            userId1 = userId,
            userId2 = matchedUser.id,
            status = MATCHED,
            matchedAt = LocalDateTime.now(),
            expireAt = LocalDateTime.now().plusMinutes(2), // 2л¶„ нғҖмһ„м•„мӣғ
        )
        val saved = matchingRepository.save(matching)

        // 4. мғҒлҢҖл°© нҒҗм—җм„ң м ңкұ°
        matchingQueueRepository.deleteById(matchedUser.queueId!!)

        // 5. мқҙлІӨнҠё л°ңн–ү
        applicationEventPublisher.publishEvent(
            MatchingCompleteEvent(saved.id, userId, matchedUser.id)
        )

        return saved
    }

    private fun findCandidates(userId: String, preferences: MatchingPreference): List<UserInfo> {
        val pendingQueues = matchingQueueRepository.findPendingQueue()
        return pendingQueues
            .filter { it.userId != userId }
            .filter { meetsPreferences(it, preferences) }
            .sortByDescending { calculateMatchScore(userId, it.userId) }
    }

    @Transactional
    fun acceptMatching(matchingId: String): MatchingEntity {
        val matching = matchingRepository.findById(matchingId)
            .orElseThrow { MatchingNotFoundException() }

        if (matching.status != PENDING_ACCEPT) {
            throw InvalidMatchingStatusException()
        }

        matching.status = ACCEPTED
        matching.acceptedAt = LocalDateTime.now()

        applicationEventPublisher.publishEvent(
            MatchingAcceptedEvent(matchingId)
        )

        return matchingRepository.save(matching)
    }

    @Scheduled(fixedDelay = 60000) // 1л¶„л§ҲлӢӨ мӢӨн–ү
    @Transactional
    fun cleanupExpiredMatching() {
        val now = LocalDateTime.now()
        val expiredMatching = matchingRepository.findExpiredMatching(now)

        expiredMatching.forEach {
            it.status = EXPIRED
            matchingRepository.save(it)

            applicationEventPublisher.publishEvent(
                MatchingExpiredEvent(it.id, it.userId1, it.userId2)
            )
        }
    }
}

@Service
class CallService(
    private val callRepository: CallRepository,
    private val matchingRepository: MatchingRepository,
    private val applicationEventPublisher: ApplicationEventPublisher,
) {

    @Transactional
    fun startCall(matchingId: String, initiatorId: String): CallEntity {
        // 1. л§Өм№ӯ кІҖмҰқ
        val matching = matchingRepository.findById(matchingId)
            .orElseThrow { MatchingNotFoundException() }

        if (matching.status != ACCEPTED) {
            throw InvalidMatchingStatusException()
        }

        // 2. нҶөнҷ” кё°лЎқ мғқм„ұ
        val call = CallEntity(
            matchingId = matchingId,
            initiatorUserId = initiatorId,
            receiverUserId = getReceiverUserId(matching, initiatorId),
            status = CALLING,
            startedAt = LocalDateTime.now(),
        )
        val savedCall = callRepository.save(call)

        // 3. мқҙлІӨнҠё л°ңн–ү (WebSocket м•ҢлҰј)
        applicationEventPublisher.publishEvent(
            CallInitiatedEvent(savedCall.id, initiatorId, savedCall.receiverUserId)
        )

        return savedCall
    }

    @Transactional
    fun endCall(callId: String, duration: Int): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { CallNotFoundException() }

        call.status = COMPLETED
        call.duration = duration
        call.endedAt = LocalDateTime.now()

        val saved = callRepository.save(call)

        // нҶөнҷ” мў…лЈҢ мқҙлІӨнҠё
        applicationEventPublisher.publishEvent(
            CallEndedEvent(callId, call.initiatorUserId, call.receiverUserId, duration)
        )

        return saved
    }
}
